// UnauthenticatedMenu.js
import React from 'react';

const UnauthenticatedMenu = ({ categories }) => {
  return (
    <ul>
      {categories.map((category, index) => (
        <li key={index}>
          <div>
            <span>{category.mainMenu}</span>
            <ul>
              {category.subMenu.map((subItem, subIndex) => (
                <li key={`${subItem._id}-${subIndex}`}>
                  <span>{subItem}</span>
                </li>
              ))}
            </ul>
          </div>
        </li>
      ))}
    </ul>
  );
};

export default UnauthenticatedMenu;
